def calculate_fibonacci(n: int) -> int:
    if not isinstance(n, int) or isinstance(n, bool):
        raise TypeError("Input 'n' must be a non-boolean integer.")
    if n < 0:
        raise ValueError("Input 'n' must be a non-negative integer.")
    if n == 0:
        return 0
    a, b = 0, 1
    for _ in range(1, n):
        a, b = b, a + b
    return b

